// Calls: idempotencyService.isProcessed(eventId)
// Blocks duplicate Telegram messages
const { isProcessed } = require('./app/js/data/idempotencyService.js');
const messageId = $input.first().json.body?.message?.message_id;
const chatId = $input.first().json.body?.message?.chat?.id;
const eventId = `tg_${messageId}`;
if (messageId && isProcessed(eventId)) {
  return [];
}
return [{ json: { ...$input.first().json, event_id: eventId, chat_id: chatId } }];

// Simple rate limiting — max 30 messages per minute per chat
// Uses $node global store for counters
return $input.all(); // Implemented in webhookHandler.js when using native bot

// Calls: aiService.parseOrderMessage(text, history)
// Returns: { product_name, quantity, desired_date, customizations, needs_clarification, ... }
const { parseOrderMessage } = require('./app/js/bot/aiService.js');
const text = $input.first().json.body?.message?.text || '';
try {
  const parsed = await parseOrderMessage(text);
  return [{ json: { ...parsed, original_text: text, event_id: $input.first().json.event_id, chat_id: $input.first().json.chat_id } }];
} catch (err) {
  return [{ json: { error: err.message, needs_clarification: true, clarification_text: 'Виникла помилка обробки. Спробуйте ще раз.' } }];
}

// Calls: orderService.createOrder(orderInput)
// All business logic (BOM, stock, calendar, pricing) happens inside
const { createOrder } = require('./app/js/orders/orderService.js');
const { sendTelegramMessage, sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const parsed = $input.first().json;
const orderInput = {
  ...parsed,
  event_id: parsed.event_id,
  source: 'telegram',
  client_contact: String(parsed.chat_id)
};
const result = createOrder(orderInput);
if (result.status === 'DUPLICATE_EVENT') {
  await sendTelegramMessage(parsed.chat_id, 'Ваше замовлення вже зареєстровано.');
} else if (result.status === 'HANDOFF_REQUIRED') {
  await sendTelegramMessage(parsed.chat_id, 'Ваш запит передано менеджеру.');
  await sendManagerAlert('🔄 Handoff: ' + JSON.stringify(result));
} else {
  const msg = `✅ Замовлення ${result.order_id} прийнято\n💰 Ціна: ${result.proposed_price} грн\n📅 Готовність: ${result.ready_date || 'уточнюється'}`;
  await sendTelegramMessage(parsed.chat_id, msg);
}
return [{ json: result }];
